import React from 'react';
import { Handle, Position } from 'reactflow';

// OutputNode: displays the AI reply or a loading/placeholder state
function OutputNode({ data }) {
  const renderContent = () => {
    if (data.loading) {
      return <p className="loading-text">⏳ Generating response...</p>;
    }
    if (data.reply) {
      return <p className="reply-text">{data.reply}</p>;
    }
    return <p className="placeholder-text">AI response will appear here after you run the flow.</p>;
  };

  return (
    <div className="custom-node output-node">
      {/* Target handle: receives connection from InputNode */}
      <Handle type="target" position={Position.Left} id="in" />
      <div className="node-header">🤖 AI Response</div>
      <div className="node-body">{renderContent()}</div>
    </div>
  );
}

export default OutputNode;
